## Objective
Implement the core SSH server that can accept connections and perform the SSH handshake using russh.

## Implementation Details

### Server Configuration
```rust
use russh::server::{Config, Server};
use russh_keys::key::KeyPair;
use std::sync::Arc;

pub struct WishServer {
    config: Arc<Config>,
    host_keys: Vec<KeyPair>,
    bind_addr: SocketAddr,
}

impl WishServer {
    pub fn new(config: WishConfig) -> Result<Self> {
        let russh_config = Config {
            inactivity_timeout: Some(Duration::from_secs(config.timeout_secs)),
            auth_rejection_time: Duration::from_secs(3),
            auth_rejection_time_initial: Some(Duration::from_secs(0)),
            keys: vec![load_or_generate_host_key(&config.host_key_path)?],
            ..Default::default()
        };

        Ok(Self {
            config: Arc::new(russh_config),
            bind_addr: config.bind_addr,
        })
    }

    pub async fn run(&self) -> Result<()> {
        log::info!("Starting SSH server on {}", self.bind_addr);
        russh::server::run(self.config.clone(), &self.bind_addr, self).await?;
        Ok(())
    }
}
```

### Connection Handler Skeleton
```rust
impl russh::server::Server for WishServer {
    type Handler = ConnectionHandler;

    fn new_client(&mut self, addr: Option<SocketAddr>) -> Self::Handler {
        log::info!("New connection from {:?}", addr);
        ConnectionHandler::new(addr)
    }
}

pub struct ConnectionHandler {
    peer_addr: Option<SocketAddr>,
}

impl russh::server::Handler for ConnectionHandler {
    type Error = WishError;

    // Stub implementations for now
}
```

### Host Key Management
```rust
fn load_or_generate_host_key(path: &Path) -> Result<KeyPair> {
    if path.exists() {
        log::debug!("Loading host key from {:?}", path);
        russh_keys::load_secret_key(path, None)
    } else {
        log::info!("Generating new Ed25519 host key at {:?}", path);
        let key = russh_keys::key::KeyPair::generate_ed25519().unwrap();
        // Save to file
        Ok(key)
    }
}
```

