```rust
// examples/derive_showcase/main.rs
//! Comprehensive example demonstrating all #[derive(Model)] features

use bubbletea::Command;
use bubbletea_macros::Model;
use lipgloss::{Color, Style};
use std::time::{Duration, Instant};

/// Application messages
#[derive(Debug, Clone)]
enum Msg {
    Tick,
    IncrementCounter,
    DecrementCounter,
    ToggleTimer,
    UpdateInput(String),
    Submit,
    Quit,
}

/// Main application model demonstrating all derive features
#[derive(Model)]
#[model(message = Msg)]  // Explicit message type
struct App {
    // Basic state field - triggers re-render on change
    #[state]
    counter: i32,

    // Another state field
    #[state]
    timer_running: bool,

    // State with custom equality (for floating point)
    #[state(eq = "duration_approx_eq")]
    elapsed: Duration,

    // Skipped state - changes don't trigger re-render
    #[state(skip)]
    last_tick: Option<Instant>,

    // Debug state - logs changes
    #[state(debug)]
    input_text: String,

    // Non-state field - never tracked
    styles: AppStyles,
}

/// Custom equality for Duration (ignore sub-millisecond differences)
fn duration_approx_eq(a: &Duration, b: &Duration) -> bool {
    a.as_millis() == b.as_millis()
}

struct AppStyles {
    title: Style,
    counter: Style,
    timer: Style,
}

impl Default for AppStyles {
    fn default() -> Self {
        Self {
            title: Style::new().bold(true).foreground(Color::Cyan),
            counter: Style::new().foreground(Color::Green),
            timer: Style::new().foreground(Color::Yellow),
        }
    }
}

impl App {
    /// Initialize the application
    #[init]
    fn init() -> (Self, Command<Msg>) {
        charmed_log::info!("Initializing App");

        (
            App {
                counter: 0,
                timer_running: false,
                elapsed: Duration::ZERO,
                last_tick: None,
                input_text: String::new(),
                styles: AppStyles::default(),
            },
            Command::none(),
        )
    }

    /// Handle incoming messages
    #[update]
    fn update(&mut self, msg: Msg) -> Command<Msg> {
        charmed_log::debug!("Received: {:?}", msg);

        match msg {
            Msg::Tick if self.timer_running => {
                if let Some(last) = self.last_tick {
                    self.elapsed += last.elapsed();
                }
                self.last_tick = Some(Instant::now());
                return self.tick_command();
            }

            Msg::IncrementCounter => {
                self.counter = self.counter.saturating_add(1);
            }

            Msg::DecrementCounter => {
                self.counter = self.counter.saturating_sub(1);
            }

            Msg::ToggleTimer => {
                self.timer_running = !self.timer_running;
                if self.timer_running {
                    self.last_tick = Some(Instant::now());
                    return self.tick_command();
                } else {
                    self.last_tick = None;
                }
            }

            Msg::UpdateInput(text) => {
                self.input_text = text;
            }

            Msg::Submit => {
                charmed_log::info!("Submitted: {}", self.input_text);
                self.input_text.clear();
            }

            Msg::Quit => {
                return Command::quit();
            }

            _ => {}
        }

        Command::none()
    }

    /// Render the view
    #[view]
    fn view(&self) -> String {
        let timer_status = if self.timer_running { "▶" } else { "⏸" };

        format!(
            "{}\n\n\
             Counter: {}\n\
             Timer: {} {:.1}s\n\
             Input: {}\n\n\
             [+/-] Counter  [t] Timer  [q] Quit",
            self.styles.title.render("Derive Showcase"),
            self.styles.counter.render(&self.counter.to_string()),
            timer_status,
            self.elapsed.as_secs_f64(),
            self.input_text,
        )
    }

    fn tick_command(&self) -> Command<Msg> {
        Command::perform(
            async { tokio::time::sleep(Duration::from_millis(100)).await },
            |_| Msg::Tick,
        )
    }
}

#[tokio::main]
async fn main() -> anyhow::Result<()> {
    // Initialize logging
    charmed_log::init(charmed_log::Level::Debug)?;

    bubbletea::run(App::init)
}
