```rust
use std::sync::Arc;
use lipgloss::{Style, Theme, ThemeContext, ColorSlot, Color};

/// A style that automatically resolves colors from the current theme
#[derive(Clone)]
pub struct ThemedStyle {
    context: Arc<ThemeContext>,
    foreground: Option<ThemedColor>,
    background: Option<ThemedColor>,
    border_foreground: Option<ThemedColor>,
    border_background: Option<ThemedColor>,
    // Other style properties that don't depend on theme
    base_style: Style,
}

/// Color that can be either a fixed value or a theme slot
#[derive(Clone)]
pub enum ThemedColor {
    /// Fixed color value
    Fixed(Color),
    /// Color resolved from theme at render time
    Slot(ColorSlot),
    /// Computed color (e.g., lighter/darker variant)
    Computed(ColorSlot, ColorTransform),
}

#[derive(Clone, Copy)]
pub enum ColorTransform {
    Lighten(f32),  // 0.0-1.0
    Darken(f32),
    Saturate(f32),
    Desaturate(f32),
    Alpha(f32),
}

impl ThemedStyle {
    /// Create a new themed style with a context
    pub fn new(context: Arc<ThemeContext>) -> Self {
        Self {
            context,
            foreground: None,
            background: None,
            border_foreground: None,
            border_background: None,
            base_style: Style::new(),
        }
    }

    /// Create from global theme context
    pub fn global() -> Self {
        Self::new(Arc::new(global_theme().clone()))
    }

    /// Set foreground to a theme color slot
    pub fn foreground(mut self, slot: ColorSlot) -> Self {
        self.foreground = Some(ThemedColor::Slot(slot));
        self
    }

    /// Set foreground to a fixed color (ignores theme)
    pub fn foreground_fixed(mut self, color: impl Into<Color>) -> Self {
        self.foreground = Some(ThemedColor::Fixed(color.into()));
        self
    }

    /// Set foreground to a computed theme color
    pub fn foreground_computed(mut self, slot: ColorSlot, transform: ColorTransform) -> Self {
        self.foreground = Some(ThemedColor::Computed(slot, transform));
        self
    }

    /// Set background to a theme color slot
    pub fn background(mut self, slot: ColorSlot) -> Self {
        self.background = Some(ThemedColor::Slot(slot));
        self
    }

    // ... similar methods for other colors

    /// Apply non-color style properties
    pub fn bold(mut self, v: bool) -> Self {
        self.base_style = self.base_style.bold(v);
        self
    }

    pub fn italic(mut self, v: bool) -> Self {
        self.base_style = self.base_style.italic(v);
        self
    }

    pub fn padding(mut self, v: u16) -> Self {
        self.base_style = self.base_style.padding(v);
        self
    }

    // ... delegate other non-color methods to base_style
}
```

### 2. Render-time Resolution
Resolve colors at render time from current theme:

```rust
impl ThemedStyle {
    /// Resolve the themed style to a concrete Style using current theme
    pub fn resolve(&self) -> Style {
        let theme = self.context.current();
        let mut style = self.base_style.clone();

        if let Some(ref fg) = self.foreground {
            style = style.foreground(self.resolve_color(fg, &theme));
        }
        if let Some(ref bg) = self.background {
            style = style.background(self.resolve_color(bg, &theme));
        }
        if let Some(ref bfg) = self.border_foreground {
            style = style.border_foreground(self.resolve_color(bfg, &theme));
        }
        if let Some(ref bbg) = self.border_background {
            style = style.border_background(self.resolve_color(bbg, &theme));
        }

        style
    }

    fn resolve_color(&self, themed: &ThemedColor, theme: &Theme) -> Color {
        match themed {
            ThemedColor::Fixed(c) => c.clone(),
            ThemedColor::Slot(slot) => theme.get(*slot),
            ThemedColor::Computed(slot, transform) => {
                let base = theme.get(*slot);
                transform.apply(base)
            }
        }
    }

    /// Render text with the themed style (resolves at call time)
    pub fn render(&self, text: &str) -> String {
        self.resolve().render(text)
    }
}

impl ColorTransform {
    fn apply(&self, color: Color) -> Color {
        match self {
            ColorTransform::Lighten(amount) => color.lighten(*amount),
            ColorTransform::Darken(amount) => color.darken(*amount),
            ColorTransform::Saturate(amount) => color.saturate(*amount),
            ColorTransform::Desaturate(amount) => color.desaturate(*amount),
            ColorTransform::Alpha(alpha) => color.with_alpha(*alpha),
        }
    }
}
```

### 3. Caching for Performance
Implement optional caching to avoid repeated resolution:

```rust
use std::sync::atomic::{AtomicU64, Ordering};

pub struct CachedThemedStyle {
    themed: ThemedStyle,
    cache: RwLock<Option<(u64, Style)>>,
}

impl CachedThemedStyle {
    pub fn new(themed: ThemedStyle) -> Self {
        Self {
            themed,
            cache: RwLock::new(None),
        }
    }

    pub fn resolve(&self) -> Style {
        let theme_version = self.themed.context.version();

        // Check cache
        {
            let cache = self.cache.read().unwrap();
            if let Some((cached_version, ref style)) = *cache {
                if cached_version == theme_version {
                    return style.clone();
                }
            }
        }

        // Cache miss - resolve and store
        let resolved = self.themed.resolve();
        {
            let mut cache = self.cache.write().unwrap();
            *cache = Some((theme_version, resolved.clone()));
        }
        resolved
    }

    pub fn invalidate(&self) {
        let mut cache = self.cache.write().unwrap();
        *cache = None;
    }
}
```

