    inner: Theme,
    /// Pre-computed lipgloss styles for common scopes
    cache: HashMap<String, Style>,
}

impl SyntaxTheme {
    /// Load a built-in theme by name
    pub fn from_name(name: &str) -> Option<Self> {
        let ts = ThemeSet::load_defaults();
        ts.themes.get(name).map(|theme| Self {
            inner: theme.clone(),
            cache: HashMap::new(),
        })
    }

    /// Available built-in themes
