            "base16-mocha.dark",
            "InspiredGitHub",
            "Solarized (dark)",
            "Solarized (light)",
        ]
    }
}
```

### 3. Color Space Handling
```rust
/// Handle color conversion edge cases
fn convert_color(color: syntect::highlighting::Color) -> lipgloss::Color {
    // syntect uses RGBA, terminals typically support:
    // - 16 ANSI colors
    // - 256 color palette
    // - True color (24-bit RGB)

    // For maximum compatibility, we use true color
    // and let lipgloss handle downgrading for limited terminals
    lipgloss::Color::rgb(color.r, color.g, color.b)
}

/// For terminals with limited color support
fn quantize_to_256(r: u8, g: u8, b: u8) -> u8 {
    // Convert RGB to xterm-256 color code
    if r == g && g == b {
        // Grayscale
        if r < 8 { return 16; }
        if r > 248 { return 231; }
        return 232 + ((r - 8) / 10);
    }
    16 + (36 * (r / 51)) + (6 * (g / 51)) + (b / 51)
}
```

### 4. Style Caching for Performance
```rust
/// Cache converted styles to avoid repeated conversions
pub struct StyleCache {
    map: HashMap<SynStyle, Style>,
}

impl StyleCache {
    pub fn get_or_insert(&mut self, syn_style: SynStyle) -> &Style {
        self.map.entry(syn_style).or_insert_with(|| {
            syntect_to_lipgloss(syn_style)
        })
    }
}
```

