## Objective
Implement wasm-bindgen integration to expose charmed_rust APIs to JavaScript, enabling web applications to use lipgloss styling, bubbles components, and bubbletea programs.

## Detailed Requirements

### 1. Add wasm-bindgen Attributes to Core Types

```rust
// crates/lipgloss/src/style.rs

use wasm_bindgen::prelude::*;

#[wasm_bindgen]
#[derive(Clone, Debug)]
pub struct Style {
    foreground: Option<Color>,
    background: Option<Color>,
    bold: bool,
    italic: bool,
    underline: bool,
    padding: Padding,
    margin: Margin,
    // ...
}

#[wasm_bindgen]
impl Style {
    #[wasm_bindgen(constructor)]
    pub fn new() -> Self {
        Self::default()
    }

    /// Set foreground color (chainable)
    #[wasm_bindgen(js_name = "foreground")]
    pub fn foreground_js(self, color: &str) -> Self {
        self.foreground(color.parse().unwrap_or_default())
    }

    /// Set background color (chainable)
    #[wasm_bindgen(js_name = "background")]
    pub fn background_js(self, color: &str) -> Self {
        self.background(color.parse().unwrap_or_default())
    }

    #[wasm_bindgen]
    pub fn bold(self) -> Self {
        Self { bold: true, ..self }
    }

    #[wasm_bindgen]
    pub fn italic(self) -> Self {
        Self { italic: true, ..self }
    }

    #[wasm_bindgen]
    pub fn padding(self, top: u16, right: u16, bottom: u16, left: u16) -> Self {
        Self { 
            padding: Padding { top, right, bottom, left },
            ..self 
        }
    }

    /// Render content with this style (returns HTML)
    #[wasm_bindgen]
    pub fn render(&self, content: &str) -> String {
        self.render_html(content)
    }
}
```

