pub fn join_horizontal(items: Vec<JsValue>) -> String {
    let strings: Vec<String> = items
        .iter()
        .filter_map(|v| v.as_string())
        .collect();
    lipgloss::join_horizontal(lipgloss::Position::Top, &strings)
}

/// Join multiple styled strings vertically  
#[wasm_bindgen(js_name = "joinVertical")]
pub fn join_vertical(items: Vec<JsValue>) -> String {
    let strings: Vec<String> = items
        .iter()
        .filter_map(|v| v.as_string())
