use crate::key::{Key, KeyParser};
use crate::proptest::generators::ansi::*;

proptest! {
    /// Property: All valid key sequences should parse without panicking
    #[test]
    fn key_parsing_never_panics(
        seq in arb_any_key_sequence()
    ) {
        let bytes = seq.to_bytes();
        // Should never panic, even on malformed input
        let _ = KeyParser::parse(&bytes);
    }

    /// Property: Empty input should return no key
    #[test]
    fn empty_input_returns_none(
        _unused in Just(())
    ) {
        let result = KeyParser::parse(&[]);
        prop_assert!(result.is_none() || result == Some((Key::None, 0)));
    }

    /// Property: Single printable ASCII always produces Rune key
    #[test]
    fn ascii_printable_produces_rune(
        ch in 0x20u8..=0x7E  // Space to tilde
    ) {
        let result = KeyParser::parse(&[ch]);
        prop_assert!(matches!(result, Some((Key::Rune(c), 1)) if c == ch as char));
    }

    /// Property: Control characters produce Ctrl+letter
    #[test]
    fn control_chars_produce_ctrl(
        ch in 1u8..=26  // Ctrl+A through Ctrl+Z
    ) {
        let result = KeyParser::parse(&[ch]);
        let expected_char = (ch + b'a' - 1) as char;
        prop_assert!(matches!(
            result,
            Some((Key::Ctrl(c), 1)) if c == expected_char
        ));
    }
}
