    /// Property: Repeated parsing of streaming input is consistent
    #[test]
    fn streaming_parse_consistent(
        chunks in prop::collection::vec(
            prop::collection::vec(any::<u8>(), 1..20),
            1..10
        )
    ) {
        let combined: Vec<u8> = chunks.iter().flatten().copied().collect();

        // Parse combined should give same result as accumulated chunks
        let mut offset = 0;
        let mut keys_chunked = vec![];

        for chunk in &chunks {
            let available = &combined[offset..offset + chunk.len()];
            while offset < combined.len() {
                match KeyParser::parse(&combined[offset..]) {
                    Some((key, consumed)) => {
                        keys_chunked.push(key);
                        offset += consumed;
                    }
                    None => break,
                }
            }
        }

        // Result should be deterministic
        let mut keys_combined = vec![];
        offset = 0;
        while offset < combined.len() {
            match KeyParser::parse(&combined[offset..]) {
                Some((key, consumed)) => {
                    keys_combined.push(key);
                    offset += consumed;
                }
                None => break,
            }
        }

        prop_assert_eq!(keys_chunked, keys_combined);
    }
}
